import{_ as s,o as i,c as e,ae as t}from"./chunks/framework.Czhw_PXq.js";const k=JSON.parse('{"title":"macOS 系统安装","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/install/macos.md","filePath":"zh-cn/install/macos.md"}'),l={name:"zh-cn/install/macos.md"};function n(h,a,o,r,p,d){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="macos-系统安装" tabindex="-1">macOS 系统安装 <a class="header-anchor" href="#macos-系统安装" aria-label="Permalink to &quot;macOS 系统安装&quot;">​</a></h1><h2 id="应用安装" tabindex="-1">应用安装 <a class="header-anchor" href="#应用安装" aria-label="Permalink to &quot;应用安装&quot;">​</a></h2><p>由于本应用未进行 Apple 签名认证，macOS 可能会阻止安装。</p><h3 id="解决方法" tabindex="-1">解决方法 <a class="header-anchor" href="#解决方法" aria-label="Permalink to &quot;解决方法&quot;">​</a></h3><h4 id="方法一-右键打开-推荐" tabindex="-1">方法一：右键打开（推荐） <a class="header-anchor" href="#方法一-右键打开-推荐" aria-label="Permalink to &quot;方法一：右键打开（推荐）&quot;">​</a></h4><ol><li>在 Finder 中找到 <code>.app</code> 文件</li><li><strong>右键点击</strong> → <strong>打开</strong></li><li>在弹出的提示框中点击<strong>打开</strong></li></ol><h4 id="方法二-在系统设置中允许" tabindex="-1">方法二：在系统设置中允许 <a class="header-anchor" href="#方法二-在系统设置中允许" aria-label="Permalink to &quot;方法二：在系统设置中允许&quot;">​</a></h4><ol><li>首次打开应用时会看到&quot;macOS 阻止运行&quot;的提示</li><li>前往<strong>系统设置</strong> → <strong>隐私与安全性</strong></li><li>滚动到下方，点击**&quot;仍要打开&quot;**</li></ol><h4 id="方法三-允许任何来源的应用" tabindex="-1">方法三：允许任何来源的应用 <a class="header-anchor" href="#方法三-允许任何来源的应用" aria-label="Permalink to &quot;方法三：允许任何来源的应用&quot;">​</a></h4><ol><li>打开<strong>终端</strong>，执行以下命令：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --master-disable</span></span></code></pre></div><ol start="2"><li>打开<strong>系统设置</strong> → <strong>隐私与安全性</strong></li><li>滚动到&quot;安全性&quot;部分，选择&quot;任何来源&quot;</li></ol><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li><strong>操作系统</strong>: macOS 10.15 (Catalina) 或更高</li><li><strong>架构</strong>: Apple Silicon (M1/M2/M3/M4) 或 Intel</li><li><strong>磁盘空间</strong>: 约 200MB 用于 ADB</li></ul><h2 id="安装方式" tabindex="-1">安装方式 <a class="header-anchor" href="#安装方式" aria-label="Permalink to &quot;安装方式&quot;">​</a></h2><h3 id="方式一-homebrew-推荐" tabindex="-1">方式一：Homebrew（推荐） <a class="header-anchor" href="#方式一-homebrew-推荐" aria-label="Permalink to &quot;方式一：Homebrew（推荐）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> android-platform-tools</span></span></code></pre></div><h3 id="方式二-手动安装" tabindex="-1">方式二：手动安装 <a class="header-anchor" href="#方式二-手动安装" aria-label="Permalink to &quot;方式二：手动安装&quot;">​</a></h3><ol><li>下载 <a href="https://developer.android.com/studio/releases/platform-tools" target="_blank" rel="noreferrer">Android SDK Platform Tools</a> macOS 版本</li><li>解压到 <code>~/Library/Android/sdk/platform-tools/</code></li></ol><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to &quot;验证安装&quot;">​</a></h2><p>打开终端，输入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span></span></code></pre></div><p>应显示类似：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Android Debug Bridge version 1.0.41</span></span>
<span class="line"><span>Version 34.0.5-10900879</span></span></code></pre></div><h2 id="配置-path-如需要" tabindex="-1">配置 PATH（如需要） <a class="header-anchor" href="#配置-path-如需要" aria-label="Permalink to &quot;配置 PATH（如需要）&quot;">​</a></h2><p>如果使用手动安装方式，添加到 <code>~/.zshrc</code> 或 <code>~/.bash_profile</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/Library/Android/sdk/platform-tools:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>然后执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 或 source ~/.bash_profile</span></span></code></pre></div><h2 id="手机设置" tabindex="-1">手机设置 <a class="header-anchor" href="#手机设置" aria-label="Permalink to &quot;手机设置&quot;">​</a></h2><ol><li>开启手机的「开发者选项」 <ul><li>设置 → 关于手机 → 连续点击「版本号」7 次</li></ul></li><li>启用「USB 调试」 <ul><li>设置 → 开发者选项 → USB 调试</li></ul></li><li>确保手机和电脑在同一 WiFi 网络</li></ol><h2 id="adb-连接" tabindex="-1">ADB 连接 <a class="header-anchor" href="#adb-连接" aria-label="Permalink to &quot;ADB 连接&quot;">​</a></h2><h3 id="usb-连接" tabindex="-1">USB 连接 <a class="header-anchor" href="#usb-连接" aria-label="Permalink to &quot;USB 连接&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usb</span></span></code></pre></div><h3 id="wifi-连接" tabindex="-1">WiFi 连接 <a class="header-anchor" href="#wifi-连接" aria-label="Permalink to &quot;WiFi 连接&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 让手机监听 TCP 端口</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcpip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5555</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 通过 WiFi 连接</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> connect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.1.100:5555</span></span></code></pre></div>`,36)])])}const b=s(l,[["render",n]]);export{k as __pageData,b as default};
